const childWorkflows = ['CWF-310', 'CWF-320', 'CWF-330', 'CWF-340'];
let executionPlan = { workflows_to_execute: childWorkflows, current_index: 0, status: 'PLANNING', lineage_validation_required: true };
return [{ json: { ...$json, execution_plan: executionPlan, pack_orchestration: { started_at: new Date().toISOString(), expected_duration_seconds: 150 } } }];

// Capture cwf310_result after sub-workflow CWF-310
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };

acc["cwf310_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Capture cwf320_result after sub-workflow CWF-320
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
try { const c = $('Capture CWF-310 Result').first(); if (c) acc["cwf310_result"] = c.json["cwf310_result"] || c.json; } catch(e) {}
acc["cwf320_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Capture cwf330_result after sub-workflow CWF-330
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
try { const c = $('Capture CWF-310 Result').first(); if (c) acc["cwf310_result"] = c.json["cwf310_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-320 Result').first(); if (c) acc["cwf320_result"] = c.json["cwf320_result"] || c.json; } catch(e) {}
acc["cwf330_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Capture cwf340_result after sub-workflow CWF-340
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
try { const c = $('Capture CWF-310 Result').first(); if (c) acc["cwf310_result"] = c.json["cwf310_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-320 Result').first(); if (c) acc["cwf320_result"] = c.json["cwf320_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-330 Result').first(); if (c) acc["cwf330_result"] = c.json["cwf330_result"] || c.json; } catch(e) {}
acc["cwf340_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Phase-2 chain validation: pass if all children returned SUCCESS/COMPLETED.
const childResults = {
  CWF_310: $json.cwf310_result,
  CWF_320: $json.cwf320_result,
  CWF_330: $json.cwf330_result,
  CWF_340: $json.cwf340_result
};
const allHealthy = Object.values(childResults).every(r => r && (r.status === 'SUCCESS' || r.status === 'COMPLETED'));
const validationOk = allHealthy;
return [{ json: { ...$json, pack_validation: { child_results_aggregated: childResults, all_children_healthy: allHealthy, validation_ok: validationOk, route_to_error: !validationOk, phase2_acceptance: 'chain_healthy_required' } } }];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'namespace_update',
      target: 'dossier.context',
      timestamp: new Date().toISOString(),
      writer_id: 'WF-300',
      pack_context: $json.pack_context,
      child_results: $json.pack_validation.child_results_aggregated,
      audit_entry: 'context-engineering-pack-completion from WF-300'
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_pack_execution',
      pack_id: 'WF-300',
      dossier_id: $json.dossier_id,
      child_workflows_executed: ['CWF-310', 'CWF-320', 'CWF-330', 'CWF-340'],
      execution_status: 'COMPLETED',
      context_built: $json.pack_validation.context_built,
      lineage_validated: $json.pack_validation.lineage_validated,
      timestamp: new Date().toISOString()
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
const fs = require('fs');
const path = require('path');

const now = new Date().toISOString();
const completion_packet = {
  instance_id: 'WF-300-COMP-' + Date.now(),
  artifact_family: 'context_engineering_result',
  schema_version: '1.0.0',
  producer_workflow: 'WF-300',
  dossier_ref: $json.dossier_id,
  created_at: now,
  status: 'CREATED',
  payload: {
    pack_executed: 'WF-300',
    context_built: $json.pack_validation.context_built,
        lineage_validated: $json.pack_validation.lineage_validated,
    next_workflow: 'WF-400',
    child_packets: ["CWF-310_output","CWF-320_output","CWF-330_output","CWF-340_output"]
  }
};

const repoRoot = 'C:/ShadowEmpire-Git';
const dataDir = path.join(repoRoot, 'data');
const packetIndexPath = path.join(dataDir, 'se_packet_index.json');
if (!fs.existsSync(dataDir)) fs.mkdirSync(dataDir, { recursive: true });

let index = { entries: [], total_entries: 0, last_updated: now };
if (fs.existsSync(packetIndexPath)) {
  const parsed = JSON.parse(fs.readFileSync(packetIndexPath, 'utf8'));
  index = {
    ...index,
    ...parsed,
    entries: Array.isArray(parsed.entries)
      ? parsed.entries
      : (Array.isArray(parsed.packets) ? parsed.packets : [])
  };
}

index.entries.push({
  packet_id: completion_packet.instance_id,
  instance_id: completion_packet.instance_id,
  artifact_family: completion_packet.artifact_family,
  schema_version: completion_packet.schema_version,
  producer_workflow: completion_packet.producer_workflow,
  dossier_ref: completion_packet.dossier_ref,
  created_at: completion_packet.created_at,
  status: completion_packet.status,
  payload: completion_packet.payload
});
index.total_entries = index.entries.length;
index.last_updated = now;

fs.writeFileSync(packetIndexPath, JSON.stringify(index, null, 2), 'utf8');

return [{
  json: {
    workflow_id: 'WF-300',
    execution_status: 'SUCCESS',
    completion_packet,
    packet_persistence: {
      packet_index_path: packetIndexPath,
      packet_entries: index.entries.length,
      persisted_at: now
    }
  }
}];

if (!$json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-300',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: 'Pack validation failed or lineage validation failed',
    failure_context: $json.pack_validation,
    child_results: $json.pack_validation.child_results_aggregated
  }
}];
